      description: 'Sustainable thermal energy solutions for factories and heating plants.',
      features: ['Cost Effective', 'Consistent Burn', 'Eco-Compliant']
    },
    {
      id: '3',
      title: 'Sawdust Supply Chain',
      description: 'Community-driven collection model transforming waste into wealth.',
      features: ['Zero Waste', 'Local Sourcing', 'Community Income']
    }
  ],
  stats: [
    { id: 's1', value: 1500, suffix: ' tons', label: 'Waste Processed' },
    { id: 's2', value: 4500, suffix: ' mWh', label: 'Clean Energy' },
    { id: 's3', value: 300, suffix: '+', label: 'Families Supported' }
  ],
  founder: {
    name: "Aadil Mir",
    role: "Founder & CEO",
    bio: "A visionary entrepreneur from Raybagh, dedicated to solving Kashmir's energy crisis through sustainable innovation.",
    address: "Raybagh, Kashmir, J&K"
  },
  contactEmail: "info@kgf-energy.com",
  contactPhone: "+91 9906 123 456"
};

// Simulation of a database connection
let currentData: AppData = { ...initialData };

export const getData = async (): Promise<AppData> => {
  // Simulate network delay
  return new Promise((resolve) => {
    setTimeout(() => resolve(currentData), 500);
  });
};

export const updateData = async (newData: Partial<AppData>): Promise<AppData> => {
  return new Promise((resolve) => {
    currentData = { ...currentData, ...newData };
    setTimeout(() => resolve(currentData), 500);
  });
};

export const checkAuth = (password: string): boolean => {
  return password === "kgfadmin";
};

import React, { useState, useEffect } from 'react';
import { Menu, X, Leaf, ShieldCheck, User, Lock } from 'lucide-react';
import { Link, useLocation } from 'react-router-dom';

const Navigation: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Vision', href: '#vision' },
    { name: 'Model', href: '#model' },
    { name: 'Products', href: '#products' },
    { name: 'Impact', href: '#stats' },
    { name: 'Founder', href: '#founder' },
    { name: 'Contact', href: '#contact' },
  ];

  const isAdmin = location.pathname === '/admin';

  return (
    <nav
      className={`fixed w-full z-50 transition-all duration-300 ${
        scrolled || isAdmin ? 'bg-stone-900/90 backdrop-blur-md py-4 shadow-lg' : 'bg-transparent py-6'
      }`}
    >
      <div className="container mx-auto px-6 flex justify-between items-center">
        <Link to="/" className="flex items-center gap-2 group">
          <div className="w-10 h-10 bg-emerald-500 rounded-lg flex items-center justify-center text-white group-hover:bg-emerald-400 transition-colors">
            <Leaf size={24} />
          </div>
          <span className={`text-2xl font-bold tracking-tighter ${scrolled || isAdmin ? 'text-white' : 'text-white'}`}>
            KGF
          </span>
        </Link>

        {/* Desktop Nav */}
        <div className="hidden md:flex items-center gap-8">
          {!isAdmin && navLinks.map((link) => (
            <a
              key={link.name}
              href={link.href}
              className={`text-sm font-medium tracking-wide uppercase transition-colors hover:text-emerald-400 ${
                scrolled ? 'text-stone-300' : 'text-stone-100'
              }`}
            >
              {link.name}
            </a>
          ))}

          <Link to={isAdmin ? "/" : "/admin"} className="flex items-center gap-2 text-xs text-stone-400 hover:text-white transition-colors border border-stone-600 px-3 py-1 rounded-full">
             {isAdmin ? <Leaf size={12}/> : <Lock size={12} />}
             {isAdmin ? "View Site" : "Admin"}
          </Link>

          {!isAdmin && (
            <a
              href="#model"
              className="px-6 py-2 bg-emerald-600 text-white rounded-full text-sm font-semibold hover:bg-emerald-500 transition-all shadow-lg hover:shadow-emerald-500/20"
            >
              Explore Model
            </a>
          )}
        </div>

        {/* Mobile Toggle */}
        <button
          className="md:hidden text-white"
          onClick={() => setIsOpen(!isOpen)}
        >
          {isOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="absolute top-full left-0 w-full bg-stone-900 border-t border-stone-800 p-6 md:hidden flex flex-col gap-4 shadow-2xl">
          {!isAdmin && navLinks.map((link) => (
            <a
              key={link.name}
              href={link.href}
              onClick={() => setIsOpen(false)}
              className="text-stone-300 hover:text-emerald-400 text-lg font-medium"
            >
              {link.name}
            </a>
          ))}
           <Link 
            to={isAdmin ? "/" : "/admin"} 
            onClick={() => setIsOpen(false)}
            className="text-stone-400 hover:text-white text-sm mt-4 flex items-center gap-2"
           >
             {isAdmin ? "Back to Site" : "Admin Login"}
          </Link>
        </div>
      )}
    </nav>
  );
};

export default Navigation;

