                  />
                </div>
              </div>
            )}

            {activeTab === 'products' && (
               <div className="space-y-6">
                 <h3 className="text-xl font-bold text-stone-800 border-b pb-4">Product Management</h3>
                 <p className="text-stone-500 italic">Product editing is read-only in this demo preview.</p>
