              {link.name}
            </a>
          ))}
          {!isAdmin && !isHome && (
            <Link
              to="/"
              onClick={() => setIsOpen(false)}
              className="text-stone-300 hover:text-emerald-400 text-lg font-medium"
            >
              Home
            </Link>
          )}
           {isAdmin && (
            <Link 
              to="/" 
              onClick={() => setIsOpen(false)}
              className="text-stone-400 hover:text-white text-sm mt-4 flex items-center gap-2"
            >
              Back to Site
            </Link>
           )}
        </div>
      )}
    </nav>
  );
};

